import{c as a,Q as i,j as s,m as t}from"./chunks/framework.DVkeSyfh.js";const u=JSON.parse('{"title":"Database and Stored Data","description":"","frontmatter":{},"headers":[],"relativePath":"database.md","filePath":"database.md","lastUpdated":1782240247000}'),o={name:"database.md"};function d(r,e,c,l,n,h){return i(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="database-and-stored-data" tabindex="-1">Database and Stored Data <a class="header-anchor" href="#database-and-stored-data" aria-label="Permalink to &quot;Database and Stored Data&quot;">​</a></h1><p>This page documents the current SQLite schema and the metadata/analysis payloads stored in SQLite. Use it when you want to understand what the app saves, what a reset removes, or why one search mode needs a particular analysis pass first.</p><h2 id="sqlite-specification" tabindex="-1">SQLite Specification <a class="header-anchor" href="#sqlite-specification" aria-label="Permalink to &quot;SQLite Specification&quot;">​</a></h2><p>The current schema version is <code>4</code>.</p><p>Existing schema version <code>2</code> or <code>3</code> library databases are not migrated automatically by the app. For v2 databases, run the standalone v3 migration script first, with dry-run as the default mode:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scripts\\migrate_database_v3.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db .\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\library.sqlite</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scripts\\migrate_database_v3.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db .\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\library.sqlite </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">apply</span></span></code></pre></div><p>The script creates an online SQLite backup before <code>--apply</code>. Close the running app before applying the migration to the same database. The same script also backfills the v3 FTS search table for databases that were already migrated to v3 before the FTS index existed; this is still an explicit script action, not a runtime migration.</p><p>Schema v4 is created as an explicit one-off copy from a complete v3 library database. The source v3 file is opened read-only, the destination must be a new path unless <code>--force</code> is supplied, and the app does not perform this conversion at runtime:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scripts\\create_library_v4_from_v3.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">source .\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\library_v3.sqlite </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dest .\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\library_v4.sqlite</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scripts\\create_library_v4_from_v3.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">source .\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\library_v3.sqlite </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dest .\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\library_v4.sqlite </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">apply</span></span></code></pre></div><p>The database is local user state. Normal scan, analysis, search, reset, clear, and relocation workflows modify SQLite records only; they do not rewrite audio files. The explicit exception is the separate MAEST genre tag write workflow, which is documented in <a href="./search-and-tags.html">Search &amp; Tags</a>.</p><h3 id="tracks" tabindex="-1"><code>tracks</code> <a class="header-anchor" href="#tracks" aria-label="Permalink to &quot;`tracks`&quot;">​</a></h3><p>Stores one row per indexed audio file:</p><ul><li><code>id</code>: stable local track ID.</li><li><code>path</code>: unique stored audio path.</li><li><code>size</code>: file size at scan time.</li><li><code>mtime</code>: file modification time at scan time.</li><li><code>artist</code>, <code>title</code>, <code>album</code>: selected file metadata.</li><li><code>bpm</code>, <code>musical_key</code>, <code>energy</code>, <code>duration</code>: working fields used by the UI and analysis flows.</li><li><code>has_sonara_analysis</code>, <code>has_maest_embedding</code>, <code>has_mert_embedding</code>, <code>has_clap_embedding</code>: derived presence flags maintained by analysis writes and resets. They speed up library summary counters and missing-analysis candidate selection. They represent stored analysis presence, not a stale/fresh policy.</li><li><code>metadata_json</code>: JSON object for Mutagen fields and model-derived metadata.</li><li><code>created_at</code>, <code>updated_at</code>: local row timestamps.</li></ul><p><code>metadata_json</code> must be valid JSON. The schema has triggers to reject invalid JSON on insert or update.</p><p>The v3 schema includes partial indexes for both missing and present analysis flags. These indexes are used by library summary counters and by analyzer candidate selection, so running analysis on a mostly complete large library does not need to scan the full <code>tracks</code> table to find the small set of missing SONARA, MAEST, MERT, or CLAP rows.</p><p>Use this table to answer &quot;what tracks are in the library?&quot; and &quot;what metadata or analysis summaries does the UI show for a row?&quot; The <code>path</code> is the link back to the local audio file; relocation updates that stored path only when the same files moved to a new root.</p><h3 id="embeddings" tabindex="-1"><code>embeddings</code> <a class="header-anchor" href="#embeddings" aria-label="Permalink to &quot;`embeddings`&quot;">​</a></h3><p>Stores model vectors by track and embedding space:</p><ul><li><code>track_id</code>: references <code>tracks.id</code>.</li><li><code>embedding_key</code>: currently <code>mert</code>, <code>clap</code>, or <code>maest</code>.</li><li><code>model_name</code>: model or checkpoint identifier.</li><li><code>dim</code>: vector dimension.</li><li><code>vector</code>: binary float32 vector payload.</li><li><code>updated_at</code>: local row timestamp.</li></ul><p>The primary key is <code>(track_id, embedding_key)</code>, so the same track can have MERT, CLAP, and MAEST vectors without mixing those spaces.</p><p>Use this table to check whether an embedding-backed workflow has enough data: MERT search needs <code>mert</code>, CLAP text search needs <code>clap</code>, and promoted combined classifiers need <code>mert</code> plus <code>maest</code> alongside Sonara features.</p><h3 id="library-settings" tabindex="-1"><code>library_settings</code> <a class="header-anchor" href="#library-settings" aria-label="Permalink to &quot;`library_settings`&quot;">​</a></h3><p>Stores local database-level settings such as the selected music root.</p><p>Use this table for app-level preferences tied to one database rather than one track.</p><h3 id="track-likes" tabindex="-1"><code>track_likes</code> <a class="header-anchor" href="#track-likes" aria-label="Permalink to &quot;`track_likes`&quot;">​</a></h3><p>Stores the local liked-track list:</p><ul><li><code>track_id</code>: references <code>tracks.id</code>.</li><li><code>liked_at</code>: local timestamp for the latest like action.</li></ul><p>The primary key is <code>track_id</code>, so a track is either liked or not liked. Rows are deleted automatically when the related track is removed from the local library database. Likes are app state only; they never write to audio files or Mutagen tags.</p><h3 id="track-classifier-scores" tabindex="-1"><code>track_classifier_scores</code> <a class="header-anchor" href="#track-classifier-scores" aria-label="Permalink to &quot;`track_classifier_scores`&quot;">​</a></h3><p>Stores derived outputs from promoted Rhythm Lab classifier profiles by track and classifier key. It is not used for <code>dj-sim eval profile-sources</code> automatic score profiles, which remain JSON report artifacts outside SQLite:</p><ul><li><code>track_id</code>: references <code>tracks.id</code>.</li><li><code>classifier</code>: classifier key such as <code>live_instrumentation</code>.</li><li><code>score</code>: primary user-facing score used for filtering.</li><li><code>label</code>: coarse label such as <code>high</code>, <code>medium</code>, or <code>low</code>.</li><li><code>confidence</code>: maximum class probability from that promoted classifier output; it is not calibrated confidence and is unrelated to automatic source-profile weights.</li><li><code>probabilities_json</code>: classifier probabilities keyed by the profile&#39;s training labels.</li><li><code>feature_set</code>: feature family used by the classifier artifact, currently <code>combined</code>.</li><li><code>model_id</code>: promoted model path used for scoring.</li><li><code>analyzed_at</code>: local scoring timestamp.</li></ul><p>The primary key is <code>(track_id, classifier)</code>, so rerunning a classifier updates the score for that track instead of appending historical rows.</p><p>Use this table when a CLASS filter does not behave as expected. Missing rows usually mean the promoted classifier has not scored that track yet, or the track was missing required Sonara, MERT, or MAEST inputs during scoring.</p><h3 id="track-search-fts" tabindex="-1"><code>track_search_fts</code> <a class="header-anchor" href="#track-search-fts" aria-label="Permalink to &quot;`track_search_fts`&quot;">​</a></h3><p>Stores a derived FTS5 index for explicit token-based library search:</p><ul><li><code>track_id</code>: stable local track ID, stored unindexed for joins back to <code>tracks.id</code>.</li><li><code>search_text</code>: materialized artist, title, album, path, and <code>metadata_json</code> text.</li></ul><p>The default library search still uses substring <code>LIKE</code> semantics. FTS is used only when the caller explicitly requests <code>search_mode=fts</code>. FTS token matching can make broad count and filter work much cheaper, but sorted first pages can still be dominated by the library-order sort when the token is very common. Scan/upsert, RefreshTags, MAEST genre saves, Sonara metadata saves, resets that edit metadata, library relocation, and clear-library operations maintain the FTS rows in the same SQLite write transaction as the related <code>tracks</code> update.</p><h3 id="evaluation-and-calibration-tables" tabindex="-1">Evaluation and calibration tables <a class="header-anchor" href="#evaluation-and-calibration-tables" aria-label="Permalink to &quot;Evaluation and calibration tables&quot;">​</a></h3><p>Schema v4 adds local evaluation tables for future search-quality and transition calibration work:</p><ul><li><code>search_sessions</code>: one row per explicitly recorded evaluation search request, with JSON seed track IDs and request payload.</li><li><code>search_result_events</code>: ranked result rows tied to a recorded search session and candidate track, with a JSON score breakdown.</li><li><code>track_pair_feedback</code>: manual or tool-sourced ratings for seed/candidate pairs. Ratings are <code>0</code> through <code>3</code>; reason tags are stored as JSON. The unique key is <code>(seed_track_id, candidate_track_id, source)</code> so repeated feedback from the same source updates the same row.</li><li><code>transition_feedback</code>: append-only ratings and risk tags for outgoing/incoming transition pairs.</li><li><code>calibration_runs</code>: diagnostic/report-only calibration profile/config/metrics JSON snapshots.</li></ul><p>These rows are app evaluation data only. They are not Rhythm Lab classifier labels, not <code>track_likes</code>, and not file tags. Foreign keys cascade when related local <code>tracks</code> or <code>search_sessions</code> rows are removed. Recording evaluation data updates SQLite only and never writes to audio files.</p><p>Manual pair and transition feedback can be imported with <code>dj-sim eval</code> commands from CSV or JSONL files. These CSVs/JSONL files are optional audit and validation inputs, not classifier training data, and automatic source profiling does not require them. Search-quality reports use only explicit evaluation feedback plus already recorded search sessions/result events; likes and Rhythm Lab labels are not treated as ground truth by default.</p><p><code>dj-sim eval export-candidates</code> can create blinded manual-labeling CSVs from existing exact MERT, MAEST, and balanced SONARA search sources. With session recording enabled, it stores one <code>evaluation_candidate_pool</code> search session per seed and records the blinded candidate order in <code>search_result_events</code>; the score breakdown contains source ranks/scores and <code>blind_rank</code>. The generated CSV still requires human ratings before <code>import-pair-feedback</code> turns those rows into ground truth.</p><p><code>dj-sim eval run-calibration</code> builds diagnostic calibration JSON from recorded candidate-pool events and imported pair feedback. It records nothing by default; with explicit <code>--record</code>, only an <code>ok</code> summary is inserted into <code>calibration_runs</code> using profile <code>manual_feedback</code>. Raw scores and RRF-derived diagnostic scores are stored and reported as diagnostics, not as production confidence or probabilities, and calibration reports do not change runtime search weights or thresholds.</p><p><code>dj-sim eval profile-sources</code> is the automatic unsupervised source profiling path. It reads existing MERT, MAEST, and SONARA analysis data for sampled seeds, computes coverage, rank agreement, RRF-style consensus support, conflicts, score quantiles, and normalized internal source weights. It does not write to the database, does not use manual labels as required ground truth, does not calibrate probabilities, and does not prove human DJ taste without external validation.</p><p><code>dj-sim eval profile-sources --profile-output &lt;json&gt;</code> saves those normalized internal weights as a schema-validated JSON score profile artifact, usually under <code>reports/experiments/</code> or another user-selected reports path. Schema validation checks the artifact shape only; it is not external validation of human DJ taste. Score profiles are not stored in SQLite in schema v4, do not create a schema v5 migration, do not train classifiers, and do not change production search endpoints. <code>dj-sim eval apply-score-profile --profile &lt;json&gt;</code> applies the artifact to recorded candidate pools with weighted RRF over stored source ranks. If pair feedback exists it includes validation metrics; without labels it still reports rankings with <code>label_status: &quot;insufficient_data&quot;</code> and no quality claim.</p><h2 id="metadata-and-analysis-data" tabindex="-1">Metadata and Analysis Data <a class="header-anchor" href="#metadata-and-analysis-data" aria-label="Permalink to &quot;Metadata and Analysis Data&quot;">​</a></h2><p>The app deliberately separates file tags from computed values.</p><p>Mutagen scanning reads this fixed whitelist:</p><ul><li><code>artist</code></li><li><code>title</code></li><li><code>album</code></li><li><code>genre</code></li><li><code>year</code></li><li><code>country</code></li><li><code>label</code></li><li><code>catalog_number</code></li><li><code>track_number</code></li><li><code>disc_number</code></li><li><code>bpm</code></li><li><code>key</code></li><li><code>comment</code></li><li><code>isrc</code></li><li><code>duration</code></li><li><code>audio_format</code></li><li><code>audio_codec</code></li><li><code>date</code></li></ul><p>Values are normalized into JSON-safe values before being stored. Mutagen-specific objects such as ID3 timestamps are converted to strings.</p><p><code>RefreshTags</code> replaces only this Mutagen metadata subset. It preserves stored paths and model analysis data.</p><p>Analysis outputs live beside those file tags instead of replacing them. This is why a track can show both file metadata such as <code>genre</code> or <code>bpm</code> and computed values such as Sonara BPM, MAEST genres, embeddings, or classifier scores.</p>',53)])])}const k=a(o,[["render",d]]);export{u as __pageData,k as default};
